export function getQuizzesByTopic(topicId: string): QuizQuestion[] {
  return quizzes.filter((q) => q.topicId === topicId);
}

export function getAllQuizzes(): QuizQuestion[] {
  return quizzes;
}

export function getQuizById(id: string): QuizQuestion | undefined {
  return quizzes.find((q) => q.id === id);
}

export function getRandomQuizzes(count: number, excludeIds?: string[]): QuizQuestion[] {
  const pool = excludeIds
    ? quizzes.filter((q) => !excludeIds.includes(q.id))
    : [...quizzes];
  const shuffled = pool.sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
}
